 47→
 48→	/**
 49→	 * Dynamic loader for accumulator classes
 50→	 */
 51→	private IObjectLoader<IAccumulator> accLoader = new ObjectLoaderPath<IAccumulator>(
 52→		(params)->{
 53→			return new IAccumulator() {
 54→
 55→				@Override
 56→				public void accumulate(Object x) {
 57→					logger.log(LogLevel.ERROR, "Error accumulator: x = "+x);
