 65→			};
 66→		},
 67→		"provided.listFW.visitors.",
 68→		"visitorDemoExercises.listFWVisitorExercises.model.visitors."
 69→	);
 70→	
 71→	/**
 72→	 * Dynamic loader for visitor classes
 73→	 */
 74→	private IObjectLoader<IListAlgo> visLoader = new ObjectLoaderPath<IListAlgo>(
 75→		(params)->{
 76→			return new IListAlgo() {
 77→
 78→				@Override
 79→				public Object emptyCase(MTList host, Object... inp) {
 80→					return "Error algo: Empty case";
 81→				}
 82→
 83→				@Override
 84→				public Object nonEmptyCase(NEList host, Object... inp) {
 85→					return "Error algo: Non-empty case";
 86→				}
 87→				
 88→			};
 89→		},
 90→		"provided.listFW.visitors.",
 91→		"visitorDemoExercises.listFWVisitorExercises.model.visitors."
 92→	);
