138→	 * @param param A constructor parameter for an accumulator object.   Must be a String that the constructor can then convert to whatever it needs.
139→	 * @return The result of the foldr visitor execution by the list.
140→	 */
141→	public String runFoldR(IList list, String classname, String param) {
142→		Object [] params;
143→		if("".equals(param)) {
144→			params = new Object[] {};
145→		}
146→		else {
147→			params = new Object[] {param};
148→		}
149→		
150→		IAccumulator acc = accLoader.loadInstance(classname, params);
151→		return list + ".execute(FoldRAlgo," + classname + "(" + acc + ")) = "
