160→	 * @return The result of the foldl visitor execution by the list.
161→	 */
162→	public String runFoldL(IList list, String classname, String param) {
163→
164→		Object [] params;
165→		if("".equals(param)) {
166→			params = new Object[] {};
167→		}
168→		else {
169→			params = new Object[] {param};
170→		}
171→		
172→		IAccumulator acc = accLoader.loadInstance(classname, params);
173→		return list + ".execute(FoldLAlgo," + classname + "(" + acc + ")) = "
174→				+ list.execute(foldl, acc);
175→	}
