 1→package provided.extvisitor;
 2→
 3→import java.util.*;
 4→
 5→/**
 6→ * Abstract implementation of IExtVisitor that adds an invariant implementation of
 7→ * storing commands associated with each case in a dictionary indexed by the
 8→ * case's associated index value.
 9→ * @param <R> The type of the return value
10→ * @param <I> The type of the index value
11→ * @param <P> The type of the input parameters
12→ * @param <H> The type of the host
13→ * @author Stephen Wong (c) 2010
14→ */
15→public abstract class AExtVisitor<R, I, P, H extends IExtVisitorHost<I, ? extends H>> implements IExtVisitor<R, I, P, H> {
16→
17→	private static final long serialVersionUID = 4445948668748598430L;
18→
19→	private Map<I, IExtVisitorCmd<R, I, P, H>> cmds = new Hashtable<I, IExtVisitorCmd<R, I, P, H>>();
20→
21→	private IExtVisitorCmd<R, I, P, H> defaultCmd;
22→
23→	public AExtVisitor(IExtVisitorCmd<R, I, P, H> defaultCmd) {
24→		this.defaultCmd = defaultCmd;
25→	}
26→
27→	public AExtVisitor(final R noOpResult) {
28→		this(new IExtVisitorCmd<R, I, P, H>() {
29→
30→			private static final long serialVersionUID = -3773477471593844489L;
31→
32→			public <T extends IExtVisitorHost<I, ? extends H>> R apply(I index, T host,
33→					@SuppressWarnings("unchecked") P... params) {
34→				return noOpResult;
35→			}
36→		});
37→	}
38→
39→	public void setCmd(I idx, IExtVisitorCmd<R, I, P, H> cmd) {
40→		cmds.put(idx, cmd);
41→	}
42→
43→	public IExtVisitorCmd<R, I, P, H> getCmd(I idx) {
44→		return cmds.get(idx);
45→	}
46→
47→	public IExtVisitorCmd<R, I, P, H> removeCmd(I idx) {
48→		return cmds.remove(idx);
49→	}
50→
51→	public IExtVisitorCmd<R, I, P, H> getDefaultCmd() {
52→		return defaultCmd;
53→	}
54→
55→	public void setDefaultCmd(IExtVisitorCmd<R, I, P, H> defaultCmd) {
56→		this.defaultCmd = defaultCmd;
57→	}
58→
59→	@Override
60→	public <T extends IExtVisitorHost<I, ? extends H>> R caseAt(I idx, T host,
61→			@SuppressWarnings("unchecked") P... params) {
62→		IExtVisitorCmd<R, I, P, H> cmd = cmds.get(idx);
63→		if (cmd == null)
64→			return defaultCmd.apply(idx, host, params);
65→		else
66→			return cmd.apply(idx, host, params);
67→	}
68→
69→	public Set<I> getAllIndices() {
70→		return cmds.keySet();
71→	}
72→
73→}
74→

