23→/**
24→ * JUnit 5 tests for the list visitor algorithms in HW06.
25→ * The list framework uses the Visitor design pattern:
26→ *   - MTList.Singleton is the empty list
27→ *   - new NEList(first, rest) is a non-empty list (cons cell)
28→ *   - list.execute(algo, params...) calls algo.emptyCase or algo.nonEmptyCase
29→ */
30→class ListVisitorTest {
31→
32→    /**
33→     * Helper to build a list of integers from varargs.
34→     * Builds right-to-left: list(3, 1, 4) => NEList(3, NEList(1, NEList(4, MTList)))
35→     */
36→    private IList list(Integer... vals) {
37→        IList result = MTList.Singleton;
38→        for (int i = vals.length - 1; i >= 0; i--) {
39→            result = new NEList(vals[i], result);
40→        }
41→        return result;
42→    }
43→
