49→    void testLargestFwdSingleElement() {
50→        assertEquals(5, list(5).execute(new LargestFwdAlgo()),
51→                "Largest of [5] should be 5");
52→    }
53→
54→    @Test
55→    void testLargestFwdMultipleElements() {
56→        assertEquals(9, list(3, 9, 1, 7).execute(new LargestFwdAlgo()),
57→                "Largest of [3, 9, 1, 7] should be 9");
58→    }
59→
60→    @Test
61→    void testLargestFwdNegativeElements() {
62→        assertEquals(-1, list(-3, -1, -5).execute(new LargestFwdAlgo()),
63→                "Largest of [-3, -1, -5] should be -1");
64→    }
65→
66→    @Test
67→    void testLargestFwdLargestAtEnd() {
68→        assertEquals(10, list(1, 2, 3, 10).execute(new LargestFwdAlgo()),
69→                "Largest of [1, 2, 3, 10] should be 10 (at end)");
70→    }
71→
72→    // ---------------------------------------------------------------
73→    // LastFwdAlgo tests (forward accumulation to find last element)
74→    // ---------------------------------------------------------------
75→
76→    @Test
